mapper.select:
select count(1) as total
from projects p


        and DATE_FORMAT(p.create_time,'%Y') = #{year}


        and DATE_FORMAT(create_time,'%m') = #{month}

select IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '01' THEN 1 else 0 end ),0) as jan, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '02' THEN 1 else 0 end ),0) as feb, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '03' THEN 1 else 0 end ),0) as mar, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '04' THEN 1 else 0 end ),0) as apr, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '05' THEN 1 else 0 end ),0) as may, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '06' THEN 1 else 0 end ),0) as jun, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '07' THEN 1 else 0 end ),0) as jul, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '08' THEN 1 else 0 end ),0) as aug, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '09' THEN 1 else 0 end ),0) as sept, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '10' THEN 1 else 0 end ),0) as oct, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '11' THEN 1 else 0 end ),0) as nov, IFNULL(sum(case DATE_FORMAT(p.create_time,"%m") WHEN '12' THEN 1 else 0 end ),0) as december from projects p
and DATE_FORMAT(p.create_time,'%Y') = #{year}
and DATE_FORMAT(p.create_time,'%m') = #{month}

SELECT count(1) as task_total, IFNULL(sum(case tp.`status` WHEN 0 THEN 1 else 0 end ),0) as task_begin, IFNULL(sum(case tp.`status` WHEN 2 THEN 1 else 0 end ),0) as task_end FROM trial_task_prod tp
and DATE_FORMAT(tp.create_time,'%Y') = #{year}
and DATE_FORMAT(tp.create_time,'%m') = #{month}

select count(1) as total,
IFNULL(sum(case td.`status` WHEN 2 THEN 1 else 0 end ),0) as card_begin,
IFNULL(sum(case td.`status` WHEN 3 THEN 1 else 0 end ),0) as card_end
from trial_task_detail_prod td


        and DATE_FORMAT(td.create_time,'%Y') = #{year}


        and DATE_FORMAT(td.create_time,'%m') = #{month}

SELECT IFNULL(sum(case WHEN tp.`status`= 0 and al.action_type = 2 THEN 1 else 0 end ),0) as task_change_begin, IFNULL(sum(case WHEN tp.`status`= 2 and al.action_type = 2 THEN 1 else 0 end ),0) as task_change_end, IFNULL(sum(case WHEN tp.`status`= 0 and al.action_type = 1 THEN 1 else 0 end ),0) as task_shunt_begin, IFNULL(sum(case WHEN tp.`status`= 2 and al.action_type = 1 THEN 1 else 0 end ),0) as task_shunt_end from action_log al left join trial_task_prod tp on tp.task_id = al.task_id
and DATE_FORMAT(al.create_time,'%Y') = #{year}
and DATE_FORMAT(al.create_time,'%m') = #{month}

select sum(td.trial_quantity) as total, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '01' THEN td.trial_quantity else 0 end ),0) as jan, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '02' THEN td.trial_quantity else 0 end ),0) as feb, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '03' THEN td.trial_quantity else 0 end ),0) as mar, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '04' THEN td.trial_quantity else 0 end ),0) as apr, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '05' THEN td.trial_quantity else 0 end ),0) as may, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '06' THEN td.trial_quantity else 0 end ),0) as jun, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '07' THEN td.trial_quantity else 0 end ),0) as jul, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '08' THEN td.trial_quantity else 0 end ),0) as aug, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '09' THEN td.trial_quantity else 0 end ),0) as sept, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '10' THEN td.trial_quantity else 0 end ),0) as oct, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '11' THEN td.trial_quantity else 0 end ),0) as nov, IFNULL(sum(case DATE_FORMAT(td.create_time,"%m") WHEN '12' THEN td.trial_quantity else 0 end ),0) as december from trial_task_detail_prod td
and DATE_FORMAT(td.create_time,'%Y') = #{year}
and DATE_FORMAT(td.create_time,'%m') = #{month}

SELECT tp.task_id, tp.project_id, tp.project_name, tp.card_type, tp.title, tp.car_type, tp.assembly_name, tp.assembly_figure, tp.pm, tp.pe, tp.current_serial_no, tp.current_serial_name, tp.status, tp.create_by, tp.create_time, tp.update_by, tp.update_time, tp.remark, td.id, td.task_id, td.card_type, td.column_code, td.serial_no, td.program, td.name, td.figure, td.trial_quantity, td.inspection_quantity, td.manufacturing_quality_status, td.manufacturing_area, td.director, td.director_tel, td.process_quality_status, td.me_director, td.me_director_tel, td.notes, td.STATUS, td.create_by, td.create_time, td.update_by, td.update_time, td.remark FROM trial_task_prod tp left join trial_task_detail_prod td on tp.task_id = td.task_id
and td.status = 2
and DATE_FORMAT(td.create_time,'%Y') = #{year}
and DATE_FORMAT(td.create_time,'%m') = #{month}
